#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""ATLAS BRAIN LOOP — the operational intelligence loop (the compounding learning brain).
Every cycle it: (1) READS the learning ledger (atlas.learnings) — our accumulated knowledge;
(2) reads the Guardian's live issues; (3) MATCHES each issue to a known learning (records a
recurrence) or CAPTURES it as a new learning; (4) tracks metric OUTCOMES/trends so it learns
what's improving; (5) publishes a HEARTBEAT proving it is alive AND actually read the ledger
(row count + samples). Seeded with every incident solved June 13-14 2026 so it starts smart.
The Guardian checks this heartbeat -> brain offline / not-reading-ledger = an alarm."""
import os,sys,json,time,subprocess,random,hashlib
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#') and '=' in ln:
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
ENV={}; ENV.update(envf("/etc/atlas/db.env")); ENV.update(envf("/etc/atlas/autopull.env"))
TOK=ENV.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); REPO=ENV.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
STATE="/var/lib/atlas/brain-loop-state.json"
GUARDIAN_LOCAL="/var/lib/atlas/guardian-report.json"

# --- SEED KNOWLEDGE: every incident solved this session (signature|kind|symptom|root_cause|fix|prevention|auto_safe) ---
SEED = [
 ("ddl_gridlock","gridlock","ALTER TABLE blocks many queries; lock-waiters spike","recurring ALTER TABLE ADD COLUMN (icp-rank/sweep timers) takes ACCESS EXCLUSIVE","kill stuck DDL + disable recurring-DDL timers; set lock_timeout=15s + idle_in_transaction_session_timeout","guardian kills ALTER>40s active; alerts lock_waiters>30","t"),
 ("pool_short","reliability","worker pool below expected size (e.g. QA 1/10)","instances crash on startup or were never enabled","start missing instances; fix startup crash","guardian EXPECTED_POOLS diff auto-starts","t"),
 ("crash_loop","reliability","service auto-restarting (crash loop)","code/schema bug (recursion, ALTER under lock_timeout, NameError)","diagnose error; patch tolerant (try/except); mask if persistent","guardian auto-masks after 5 cycles","t"),
 ("enrich_stalled","throughput","enrichment net rate ~0 with backlog","lock gridlock OR async engine piling stuck queries","clear gridlock; cap/stop async; rely on sync pool","guardian ENRICH_STALLED check","t"),
 ("engine_dead_schema","reliability","engine crash-looping: column does not exist","table schema mismatch vs code (source_catalog source_key)","migrate table to add+populate expected cols; restart","guardian: is-PRODUCING not just is-active","t"),
 ("dead_timer","reliability","required timer inactive (discovery/channel-1 lapsed)","timer disabled/failed; output silently stops","enable --now timer; revive","guardian EXPECTED_TIMERS diff auto-revives","t"),
 ("status_409_race","observability","metric feeds stale/wrong (0.06/min vs real)","many committers race one git branch -> 409 dropped writes","single-authority metrics-live publisher","read metrics-live not raced feeds","t"),
 ("sources_wired_not_pulling","throughput","sources wired but not ingesting rows","serial collector backlog + some dead datasets","parallelize collector; per-source tracking; retire dead","guardian new-productive-sources/day SLA","f"),
 ("connection_ceiling","reliability","pg connections saturated -> applier/worker deadlock","too many workers/async vs max_connections=100","raise max_connections to 200; cap async; pgbouncer later","guardian CONN_PRESSURE>90% alert","t"),
 ("async_recursion","reliability","async enrich workers crash on startup","_aio_running_loop() infinite self-recursion bug","patch to asyncio.get_running_loop(); engine net-negative -> keep disabled","guardian crash-loop check","t"),
 ("pg_down_oom","reliability","PostgreSQL down ~6h; all enrichment 0; pg_isready fails","OOM on 16GB box (PG + enrich pool + ~38 collectors + brain co-resident)","restart postgresql; OOMScoreAdjust=-1000 + Restart=on-failure; atlas-pg-selfheal timer; cap shared_buffers/concurrency","guardian: auto-restart PG on pg_isready fail (bounded, fail-loud) + memory headroom","t"),
 ("nrd_tier1_stall","reliability","Tier-1 birth feed (NRD) silently stalled >26h; new-domain rows 0; watchers missed it","watcher checked is-ACTIVE not output-freshness; a disabled oneshot timer isn't 'failed', just stops producing","revive the timer; per-source last-new-rows freshness SLA + auto-revive (Tier-1 tightest, loudest)","guardian EXPECTED_TIMERS + output-freshness per source","t"),
 ("pipe_wedge_oneshot","reliability","autopull deploy pipe wedged; cursor frozen; nothing deploys","OnUnitActiveSec on a oneshot doesn't re-fire; heavy synchronous deploy step; hung run; systemctl start is no-op on hung unit","use OnUnitInactiveSec; RuntimeMaxSec/TimeoutStartSec; force-restart (kill+restart) watchdog; exit-0-safe steps; no heavy work in deploy steps","guardian watches applier heartbeat freshness; deploy steps stay <1min","t"),
 ("status_push_409_blind","observability","status feed shows stale/wrong numbers; watchers act on stale data","many box processes PUT same file to one git branch -> HTTP 409 stale-SHA -> writes dropped, feed blinded","409-retry (re-GET sha) on every status write; single-authority metrics-live; trust last-seen heartbeat","read single-committer metrics-live, not raced feeds","t"),
 ("watcher_fights_trim","reliability","watcher restarts workers Claude intentionally disabled","no hold-down list; auto-heal can't tell intentional-stop from failure","add a hold-down/intent list the watcher respects","guardian respects an intentional-disable registry","t"),
 ("reenrich_outpaces_drain","throughput","enrich queue grows backwards; pending climbs, done drops","re-enrich/requeue backfill (~10k/min) outpaces enrichment drain","throttle re-enrich (batch + cadence) to <= drain; pause until pending drains","guardian: queue-going-backwards check","t"),
 ("set_prefix_psql_trap","reliability","python int() crash on 'SET\n<n>' from psql","psql query prefixed 'SET statement_timeout=...;' emits a SET line before the result","psql helper must take .split('\n')[-1]","audit every box psql helper for the SET-strip","t"),
]

def psql(q,t=15):
    try:
        r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='8s'; "+q],capture_output=True,text=True,timeout=t)
        out=r.stdout.strip()
        return (out.split('\n')[-1] if (r.returncode==0 and out) else None)
    except Exception: return None
def gh_put(path,obj):
    if not TOK: return "no-token"
    import urllib.request
    url="https://api.github.com/repos/%s/contents/%s"%(REPO,path)
    for _ in range(10):
        try:
            sha=None
            try:
                rq=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-brain"}); sha=json.load(urllib.request.urlopen(rq,timeout=15)).get("sha")
            except Exception: sha=None
            body={"message":"brain-loop","content":__import__('base64').b64encode(json.dumps(obj,indent=1,default=str).encode()).decode(),"branch":"main"}
            if sha: body["sha"]=sha
            rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-brain","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=18); return "ok"
        except Exception: time.sleep(0.5+random.random()*2)
    return "exhausted"
def q1(s):  # single-quote escape
    return s.replace("'","''")
def ensure_ledger():
    psql("""CREATE TABLE IF NOT EXISTS atlas.learnings(
        id serial PRIMARY KEY, signature text UNIQUE, kind text, symptom text, root_cause text,
        fix_action text, prevention text, auto_safe boolean DEFAULT false,
        times_seen int DEFAULT 1, first_seen timestamptz DEFAULT now(), last_seen timestamptz DEFAULT now(),
        last_outcome text)""",t=20)
    for sig,kind,sym,rc,fix,prev,a in SEED:
        psql("INSERT INTO atlas.learnings(signature,kind,symptom,root_cause,fix_action,prevention,auto_safe) VALUES('%s','%s','%s','%s','%s','%s',%s) ON CONFLICT (signature) DO NOTHING"%(sig,kind,q1(sym),q1(rc),q1(fix),q1(prev),'true' if a=='t' else 'false'),t=15)
def sig_of(issue):
    s=issue.lower()
    for key in ["lock","pool_short","crash_loop","masked_crashloop","timer_down","service_down","enrich_stalled","discovery_stale","conn_pressure"]:
        if key.replace("_"," ") in s or key in s: return key
    return "unknown_"+hashlib.md5(issue.encode()).hexdigest()[:6]
SIG_MAP={"lock":"ddl_gridlock","pool_short":"pool_short","crash_loop":"crash_loop","masked_crashloop":"crash_loop","timer_down":"dead_timer","service_down":"dead_timer","enrich_stalled":"enrich_stalled","discovery_stale":"engine_dead_schema","conn_pressure":"connection_ceiling"}
def cycle():
    ensure_ledger()
    now=int(time.time()); rep={"kind":"brain-loop","ts":now,"mode":"active"}
    # 1) READ THE LEDGER (proof of reading our knowledge)
    total=psql("SELECT count(*) FROM atlas.learnings")
    rep["ledger_rows"]=total
    rep["reading_ledger_ok"]=(total is not None and int(total)>0)
    rep["top_learnings"]=psql("SELECT string_agg(signature||'(x'||times_seen||')', ', ') FROM (SELECT signature,times_seen FROM atlas.learnings ORDER BY times_seen DESC LIMIT 6) x")
    # 2) read guardian live issues (local handoff file)
    issues=[]
    try: issues=json.load(open(GUARDIAN_LOCAL)).get("issues",[])
    except Exception: pass
    rep["guardian_issues"]=issues
    # 3) match/record each issue -> compounding knowledge
    applied=[]
    for iss in issues:
        base=sig_of(iss); sig=SIG_MAP.get(base, base)
        known=psql("SELECT signature FROM atlas.learnings WHERE signature='%s'"%sig)
        if known:
            psql("UPDATE atlas.learnings SET times_seen=times_seen+1, last_seen=now(), last_outcome='recurred:handled_by_guardian' WHERE signature='%s'"%sig)
            applied.append("known:%s"%sig)
        else:
            psql("INSERT INTO atlas.learnings(signature,kind,symptom,root_cause,fix_action,prevention,auto_safe,last_outcome) VALUES('%s','captured','%s','(auto-captured, needs diagnosis)','(pending)','(pending)',false,'new') ON CONFLICT (signature) DO UPDATE SET times_seen=atlas.learnings.times_seen+1, last_seen=now()"%(sig,q1(iss[:120])))
            applied.append("NEW_CAPTURED:%s"%sig); rep.setdefault("new_learnings",[]).append(iss[:120])
    rep["processed"]=applied
    # 4) OUTCOME / trend learning (is the system improving?)
    done=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    pull=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record")
    prosp=psql("SELECT count(*) FROM atlas.source_catalog WHERE state='WIRED'")
    st={}
    try: st=json.load(open(STATE))
    except Exception: pass
    prev=st.get("metrics",{}); dt=now-prev.get("ts",now-120)
    trends={}
    if dt>30 and done and prev.get("done"):
        try: trends["enrich_per_min"]=round((int(done)-int(prev["done"]))*60.0/dt,1)
        except Exception: pass
    if pull and prev.get("pull") is not None:
        try: trends["sources_pulling_delta"]=int(pull)-int(prev["pull"])
        except Exception: pass
    rep["trends"]=trends; rep["metrics"]={"enrich_done":done,"sources_pulling":pull,"sources_wired":prosp}
    st["metrics"]={"ts":now,"done":done,"pull":pull}; 
    try: json.dump(st,open(STATE,"w"))
    except Exception: pass
    # 5) recommendations: recurring issues the guardian keeps fixing -> flag for deeper fix
    rep["recommendations"]=psql("SELECT string_agg(signature||'(seen x'||times_seen||')',', ') FROM (SELECT signature,times_seen FROM atlas.learnings WHERE last_outcome LIKE 'recurred%' AND times_seen>=3 ORDER BY times_seen DESC LIMIT 5) x")
    # INTUITION: mine ALL history (today + previous) -> patterns, coverage, get smarter daily
    rep["intuition"]={
      "total_distinct_incidents": total,
      "auto_safe_coverage_pct": psql("SELECT round(100.0*count(*) FILTER (WHERE auto_safe)/greatest(count(*),1)) FROM atlas.learnings"),
      "most_recurrent": psql("SELECT string_agg(signature||':'||times_seen,', ') FROM (SELECT signature,times_seen FROM atlas.learnings ORDER BY times_seen DESC LIMIT 5) x"),
      "active_recently": psql("SELECT string_agg(signature,', ') FROM (SELECT signature FROM atlas.learnings WHERE last_seen > now()-interval '6 hours' ORDER BY last_seen DESC LIMIT 8) x"),
    }
    # DAILY DIGEST (once/day): review the whole ledger, record a meta-learning -> compounding daily intelligence
    day=time.strftime("%Y-%m-%d", time.gmtime(now))
    if st.get("last_digest_day")!=day:
        dig=psql("SELECT 'incidents='||count(*)||' recurring='||count(*) FILTER (WHERE times_seen>1)||' auto_safe='||count(*) FILTER (WHERE auto_safe)||' new_24h='||count(*) FILTER (WHERE first_seen>now()-interval '24 hours') FROM atlas.learnings")
        psql("INSERT INTO atlas.learnings(signature,kind,symptom,root_cause,fix_action,prevention,auto_safe,last_outcome) VALUES('daily_digest_'||to_char(now(),'YYYYMMDD'),'digest','daily intelligence digest','%s','review','compound',true,'digest') ON CONFLICT (signature) DO UPDATE SET last_seen=now(), symptom=EXCLUDED.symptom"%(q1(str(dig))[:180] if dig else 'n/a'))
        st["last_digest_day"]=day; rep["daily_digest"]=dig; rep["got_smarter_today"]=True
    rep["cycle"]=st.get("cycle",0)+1; st["cycle"]=rep["cycle"]
    try: json.dump(st,open(STATE,"w"))
    except Exception: pass
    # local heartbeat so the Guardian can verify brain is alive + reading the ledger
    try: json.dump({"ts":now,"mode":rep["mode"],"ledger_rows":rep.get("ledger_rows"),"reading_ledger_ok":rep.get("reading_ledger_ok"),"cycle":rep.get("cycle")}, open("/var/lib/atlas/brain-heartbeat.json","w"))
    except Exception: pass
    gh_put("status/hetzner/brain-loop.json",rep)
def main():
    os.makedirs("/var/lib/atlas",exist_ok=True)
    while True:
        try: cycle()
        except Exception as e:
            try: gh_put("status/hetzner/brain-loop.json",{"kind":"brain-loop","mode":"error","cycle_error":str(e),"ts":int(time.time())})
            except Exception: pass
        time.sleep(120)
if __name__=="__main__":
    try: main()
    except Exception: sys.exit(0)
